#! /usr/bin/env node

/* eslint-disable */
const { Command } = require('commander');
const program = new Command();

var path = require('path');
var shell = require('shelljs');
var fs = require('fs');
var examples = {};
var basePath = path.resolve('');
var webpackConfigPath = path.join(
  __dirname,
  './webpack-all-examples-AUTOGENERATED.config.js'
);

var buildConfig = require('./template-multiexample-config.js');
const buildExampleIndex = require('./build-example-index.js');
const buildExampleMarkdown = require('./build-example-index-markdown.js');
const rootPath = path.resolve(path.join(__dirname, '../..'));
var distDir = path.join(rootPath, '/.static-examples');
var docsDir = path.join(rootPath, '/packages/docs/docs/');

if (!fs.existsSync(distDir)) {
  console.debug('Creating directory: ' + distDir);
  fs.mkdirSync(distDir);
}

program
  .option(
    '--build',
    'Build and write examples to disk, rather than using the Rspack Dev Server'
  )
  .option(
    '--fromRoot',
    'A flag to set that this is being run from the root of the repo'
  )
  .option(
    '--packages <list>',
    'Restrict to a comma-separated list of packages under ./packages (e.g. core,tools)'
  )
  .parse(process.argv);

const options = program.opts();
const packageAllowlist = options.packages
  ? new Set(
      String(options.packages)
        .split(',')
        .map((entry) => entry.trim())
        .filter(Boolean)
    )
  : null;

function getSplitedPath(filePath) {
  return filePath.split(/[/\\]/);
}

function validPath(str) {
  return str.replace(/\\\\/g, '/');
}

const rspackBin = validPath(
  path.join(
    rootPath,
    'node_modules',
    '.bin',
    process.platform === 'win32' ? 'rspack.cmd' : 'rspack'
  )
);

// ----------------------------------------------------------------------------
// Find examples
// ----------------------------------------------------------------------------
if (options.fromRoot === true) {
  const allPackages = [
    { package: 'core', path: 'packages/core/examples', regexp: 'index.ts' },
    { package: 'tools', path: 'packages/tools/examples', regexp: 'index.ts' },
    { package: 'ai', path: 'packages/ai/examples', regexp: 'index.ts' },
    {
      package: 'labelmap-interpolation',
      path: 'packages/labelmap-interpolation/examples',
      regexp: 'index.ts',
    },
    {
      package: 'polymorphic-segmentation',
      path: 'packages/polymorphic-segmentation/examples',
      regexp: 'index.ts',
    },
    {
      package: 'dicomImageLoader',
      path: 'packages/dicomImageLoader/examples',
      regexp: 'index.ts',
    },
    {
      package: 'nifti-volume-loader',
      path: 'packages/nifti-volume-loader/examples',
      regexp: 'index.ts',
    },
    {
      package: 'adapters',
      path: 'packages/adapters/examples',
      regexp: 'index.ts',
    },
  ];

  const filteredPackages = packageAllowlist
    ? allPackages.filter((entry) => packageAllowlist.has(entry.package))
    : allPackages;

  if (packageAllowlist && filteredPackages.length === 0) {
    console.error(
      `=> Error: --packages filter matched no package in the allowlist. Provided: ${[
        ...packageAllowlist,
      ].join(',')}`
    );
    process.exit(1);
  }

  configuration = { examples: filteredPackages };
} else {
  configuration = {
    examples: [{ path: '../examples', regexp: 'index.ts' }],
  };
}

if (configuration.examples) {
  var filterExamples = [].concat(program.args).filter((i) => !!i);
  var exampleCount = 0;
  var currentExamples;

  const allExamplePaths = {};
  configuration.examples.forEach(function (entry) {
    const regexp = entry.regexp
      ? new RegExp(entry.regexp)
      : /example\/index.ts$/;
    let fullPath = path.join(basePath, entry.path ? entry.path : entry);

    examples[fullPath] = {};
    currentExamples = examples[fullPath];
    shell.cd(fullPath);
    shell
      .find('.')
      .filter(function (file) {
        return file.match(regexp);
      })
      .forEach(function (file) {
        var fullPath = getSplitedPath(file);
        var exampleName = fullPath.pop();

        while (['index.ts', 'example'].indexOf(exampleName) !== -1) {
          exampleName = fullPath.pop();
        }

        if (
          filterExamples.length === 0 ||
          filterExamples.indexOf(exampleName) !== -1
        ) {
          currentExamples[exampleName] = './' + file;
          console.debug(' -', exampleName, ':', file);
          exampleCount++;

          allExamplePaths[exampleName] = validPath(path.resolve(file));
        }
      });
  });

  if (exampleCount === 0) {
    console.error(
      `=> Error: Did not find any examples matching ${filterExamples[0]}`
    );
    process.exit(1);
    return;
  }

  // say name of running example
  const currentWD = process.cwd();
  // run the build for dicom image loader
  // shell.cd('../../dicomImageLoader');
  // shell.exec(`yarn run build:esm`);
  // shell.cd('../..');
  // shell.exec('yarn');

  // shell.cd(currentWD);

  const examplePaths = Object.values(allExamplePaths);
  const exampleNames = Object.keys(allExamplePaths);

  // Build the example index HTML and markdown
  const exampleIndexHTML = buildExampleIndex(
    exampleNames,
    examplePaths,
    validPath(rootPath)
  );
  shell.ShellString(exampleIndexHTML).to(path.join(distDir, 'index.html'));

  const exampleIndexMarkdown = buildExampleMarkdown(
    exampleNames,
    examplePaths,
    validPath(rootPath)
  );
  shell.ShellString(exampleIndexMarkdown).to(path.join(docsDir, 'examples.md'));

  if (options.build == true) {
    const conf = buildConfig(
      exampleNames,
      examplePaths,
      distDir,
      validPath(rootPath)
    );
    shell.ShellString(conf).to(webpackConfigPath);

    shell.exec(`${rspackBin} build --config ${webpackConfigPath}`);
  } else {
    shell.exec(
      `${rspackBin} serve --host 0.0.0.0 --config ${webpackConfigPath}`
    );
  }
}
